mapper.update:
update coupon set userId = #{userId,jdbcType=BIGINT}, goodsId = #{goodsId,jdbcType=BIGINT}, couponStatus = #{couponStatus,jdbcType=INTEGER}, validityTime = #{validityTime,jdbcType=TIMESTAMP}, couponPrice = #{couponPrice,jdbcType=INTEGER}, createdDate = #{createdDate,jdbcType=TIMESTAMP}, limitPrice = #{limitPrice,jdbcType=DECIMAL}, couponType = #{couponType,jdbcType=INTEGER}, couponNew = #{couponNew,jdbcType=INTEGER}, storeAddrIds = #{storeAddrIds,jdbcType=VARCHAR}, couponTitle = #{couponTitle,jdbcType=VARCHAR}
,fitCardIds = #{fitCardIds,jdbcType=VARCHAR}
where couponId = #{couponId,jdbcType=BIGINT}

mapper.select:
select couponId, userId, goodsId, couponStatus,  concat(couponPrice,'') as couponPrice, createdDate,
date_format(validityTime, '%Y-%m-%d') as validityTime, limitPrice, couponType, couponNew, storeAddrIds, couponTitle,fitCardIds
from coupon

    
      AND userId = #{userId}
    
    
        AND couponStatus = #{couponStatus}
    
    
        AND (storeAddrIds is null or storeAddrIds = '' or find_in_set(#{storeAddrId}, storeAddrIds))
    
    
        AND (limitPrice = 0 or limitPrice <= #{paySum})
    
    
        AND (fitCardIds is null or fitCardIds = '' or find_in_set(#{fitCardId}, fitCardIds))
    
    
        AND couponType in
        
            #{item}
        
    
    
        AND couponNew = #{couponNew}
    

order by couponStatus asc, createdDate desc

mapper.update:
update coupon
set couponStatus = #{couponStatus,jdbcType=INTEGER}
where couponId = #{couponId,jdbcType=BIGINT}
